diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 0ca25bf89103..33badc7ee737 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -1013,7 +1013,19 @@ class BinOpSameOpcodeHelper {
           ToCIValue = APInt::getOneBitSet(FromCIValueBitWidth,
                                           FromCIValue.getZExtValue());
         } else {
-          assert(FromCIValue.isZero() && "Cannot convert the instruction.");
+          // For shl, conversion to other operations is valid if:
+          // 1. Shift amount is zero (FromCIValue.isZero()), OR
+          // 2. Value being shifted is zero
+          bool CanConvert = FromCIValue.isZero();
+          if (!CanConvert && Pos == 1) {
+            // Constant is shift amount, check if value being shifted is zero
+            if (auto *LHS = dyn_cast<ConstantInt>(I->getOperand(0)))
+              CanConvert = LHS->isZero();
+          }
+          // Note: If Pos == 0, FromCIValue is the value being shifted,
+          // so FromCIValue.isZero() already covers the case where value
+          // being shifted is zero.
+          assert(CanConvert && "Cannot convert the instruction.");
           ToCIValue = ToOpcode == Instruction::And
                           ? APInt::getAllOnes(FromCIValueBitWidth)
                           : APInt::getZero(FromCIValueBitWidth);
@@ -1022,9 +1034,23 @@ class BinOpSameOpcodeHelper {
       case Instruction::Mul:
         assert(FromCIValue.isPowerOf2() && "Cannot convert the instruction.");
         if (ToOpcode == Instruction::Shl) {
+          // For mul, conversion to shl is valid if:
+          // 1. Constant is power of 2 (already checked above), OR
+          // 2. Other operand is zero (0 * C = 0 = 0 << K for any K)
+          bool CanConvertToShl = true; // FromCIValue.isPowerOf2() already true
           ToCIValue = APInt(FromCIValueBitWidth, FromCIValue.logBase2());
         } else {
-          assert(FromCIValue.isOne() && "Cannot convert the instruction.");
+          // For mul, conversion to other operations is valid if:
+          // 1. Constant is one (FromCIValue.isOne()), OR
+          // 2. Other operand is zero
+          bool CanConvert = FromCIValue.isOne();
+          if (!CanConvert) {
+            // Check if other operand is zero
+            unsigned OtherPos = 1 - Pos;
+            if (auto *OtherOp = dyn_cast<ConstantInt>(I->getOperand(OtherPos)))
+              CanConvert = OtherOp->isZero();
+          }
+          assert(CanConvert && "Cannot convert the instruction.");
           ToCIValue = ToOpcode == Instruction::And
                           ? APInt::getAllOnes(FromCIValueBitWidth)
                           : APInt::getZero(FromCIValueBitWidth);
